import{_ as e,c as t,o as r,a4 as o}from"./chunks/framework.ttppV29E.js";const i="/assets/mcp-config-import.D3WsLhsh.png",v=JSON.parse('{"title":"Import and Export","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mcp-servers/import-export.md","filePath":"docs/mcp-servers/import-export.md","lastUpdated":1777374469000}'),a={name:"docs/mcp-servers/import-export.md"},s=o('<h1 id="import-and-export" tabindex="-1">Import and Export <a class="header-anchor" href="#import-and-export" aria-label="Permalink to &quot;Import and Export&quot;">​</a></h1><p>MCP server configurations can be exported and imported as JSON. This allows you to share configurations between users or environments.</p><h2 id="exporting-a-server" tabindex="-1">Exporting a Server <a class="header-anchor" href="#exporting-a-server" aria-label="Permalink to &quot;Exporting a Server&quot;">​</a></h2><ol><li>Navigate to <strong>AI Tools &gt; MCP Servers</strong></li><li>Click the three-dot menu on the server you want to export</li><li>Select <strong>Export</strong></li></ol><p>The full server configuration is copied to your clipboard as formatted JSON. Internal fields (ID, creator, tenancy) are stripped from the export - only the portable configuration is included.</p><h2 id="importing-a-server" tabindex="-1">Importing a Server <a class="header-anchor" href="#importing-a-server" aria-label="Permalink to &quot;Importing a Server&quot;">​</a></h2><ol><li>Navigate to <strong>AI Tools &gt; MCP Servers</strong></li><li>Click the <strong>Import</strong> button in the top-right corner</li><li>Paste the exported JSON into the editor</li></ol><p><img src="'+i+'" alt="mcp"></p><ol start="4"><li>Click <strong>Import</strong></li></ol><p>The imported configuration is created as a new server. Validation errors are displayed below the editor if the JSON is malformed or contains invalid values (e.g. duplicate names, missing required fields).</p><h3 id="import-validation" tabindex="-1">Import Validation <a class="header-anchor" href="#import-validation" aria-label="Permalink to &quot;Import Validation&quot;">​</a></h3><p>The import validates the same rules as manual creation:</p><ul><li>Server name must be unique in your account</li><li>Version numbers must be valid semantic versions</li><li>Endpoint names must meet naming constraints</li><li>Resource URIs must be unique within each version</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>After importing, verify that all target endpoints exist in your account. Missing endpoints are flagged with a warning icon in the server list.</p></div><h2 id="repository-synced-servers" tabindex="-1">Repository-Synced Servers <a class="header-anchor" href="#repository-synced-servers" aria-label="Permalink to &quot;Repository-Synced Servers&quot;">​</a></h2><p>MCP servers can also be synchronised from a repository integration. These servers appear in your list with a repository icon and have restricted actions:</p><ul><li><strong>View</strong> - Read-only access to the configuration</li><li><strong>Copy URL</strong> - Copy the connection URI</li><li><strong>Copy Client Config</strong> - Copy the client configuration block</li></ul><p>You cannot edit, delete, or toggle the active state of repository-synced servers. These are managed through the source repository.</p>',18),n=[s];function l(p,c,d,h,m,u){return r(),t("div",null,n)}const f=e(a,[["render",l]]);export{v as __pageData,f as default};
